request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?holdingBin ?binName ?artifactName WHERE {
  ?holdingBin rdf:type vocab:block .
  ?holdingBin vocab:NamedElement_name ?binName .
  FILTER(CONTAINS(LCASE(STR(?binName)), "holding_bin"))

  ?holdingBin vocab:Element_ownedElement+ ?artifact .
  OPTIONAL { ?artifact vocab:NamedElement_name ?artifactName . }

  FILTER(
    EXISTS { ?artifact vocab:NamedElement_name ?n1 . FILTER(CONTAINS(LCASE(STR(?n1)), "2016")) }
    ||
    EXISTS { ?artifact vocab:NamedElement_name ?n2 . FILTER(CONTAINS(LCASE(STR(?n2)), "2017")) }
  )
}
LIMIT 25
